+        let e2 = b2.build();
+        let result = compute_distance(&e1, &e2, DistanceMetric::Manhattan);
+        // |100k - 300k| + |200k - 400k| = 200k + 200k = 400k
+        assert_eq!(result.distance_millionths, 400_000);
+        assert_eq!(result.shared_dimensions, 2);
+    }
