+#[test]
+fn ic_site_kind_display_round_trips_through_serde() {
+    for kind in IcSiteKind::ALL {
+        let json = serde_json::to_string(kind).unwrap();
+        let back: IcSiteKind = serde_json::from_str(&json).unwrap();
+        assert_eq!(*kind, back);
+    }
+}
+
+#[test]
