+    let decisions = scope.evaluate_all(&config, SecurityEpoch::from_raw(1));
+    assert_eq!(decisions.len(), 3);
+
+    // Sites 0 and 8 should continue; site 16 should deoptimise
+    let deopt_decisions: Vec<_> = decisions
